2087	async function loadBackups() {
2088	  const box = $('#backups-list');
2089	  if (!box) return;
2090	  backupsExpanded = false;
2091	  showLoading('#backups-list');
2092	  let d;
2093	  try { d = await api('/backups'); }
2094	  catch { showLoadError('#backups-list', loadBackups); return; }
2095	  // 폴더별 entries를 시각 순(최신 폴더 우선)으로 평탄화한다.
2096	  const flat = [];
2097	  for (const grp of (d.backups || [])) {
2098	    for (const e of (grp.entries || [])) flat.push({ ...e, timestamp: grp.timestamp });
2099	  }
2100	  lastBackups = flat;
2101	  renderBackups();
2102	}
