2104	function renderBackups() {
2105	  const box = $('#backups-list');
2106	  if (!box) return;
2107	  if (!lastBackups.length) {
2108	    box.innerHTML = '<div class="empty-state">아직 백업이 없습니다 — 적용/동기화하면 자동으로 생깁니다.</div>';
2109	    return;
2110	  }
2111	  const shown = backupsExpanded ? lastBackups : lastBackups.slice(0, BACKUP_SHOW);
2112	  const rows = shown.map((e, i) => {
2113	    const when = e.at ? new Date(e.at).toLocaleString() : (e.timestamp || '–');
2114	    const item = e.item ? `${esc(e.item)}` : (e.file ? esc(e.file) : '–');
2115	    const kindTool = [e.kind, e.tool].filter(Boolean).map(esc).join(' · ') || '–';
2116	    const act = e.restorable
2117	      ? `<button class="btn btn-secondary btn-sm" data-backup-restore="${i}">복구</button>`
2118	      : `<span class="badge muted" title="원위치 정보(manifest)가 없어 복구할 수 없습니다">복구 불가</span>`;
2119	    return `<div class="card backup-row ${e.restorable ? '' : 'unrestorable'}">
2120	      <div class="backup-main">
2121	        <div class="item-name">${item}</div>
2122	        <div class="item-meta">${esc(when)} · ${kindTool}${e.size != null ? ` · ${esc(String(e.size))}B` : ''}</div>
2123	        <div class="item-meta backup-target">${e.targetPath ? esc(e.targetPath) : '원위치 정보 없음'}</div>
2124	      </div>
2125	      <div class="backup-act">${act}</div>
2126	    </div>`;
2127	  }).join('');
2128	  const more = (!backupsExpanded && lastBackups.length > BACKUP_SHOW)
2129	    ? `<div class="inline-acts" style="justify-content:center"><button class="btn btn-ghost btn-sm" data-backup-more="1">더보기 (${lastBackups.length - BACKUP_SHOW})</button></div>`
2130	    : '';
2131	  box.innerHTML = rows + more;
2132	}
