// 모든 canonical 항목을 { id, name, text, type } 로 모은다(중복 탐지/표시용).
function collectItems() {
  const items = [];
  const instr = canonical.read('instr-global');
  if (instr) items.push({ id: 'instr-global', name: 'instr-global', text: instr.body, type: 'instruction' });
  for (const a of canonical.listAgents()) {
    items.push({ id: a.id, name: a.name, text: `${a.description || ''}\n${a.system_prompt || ''}`, type: 'agent' });
  }
  for (const meta of canonical.listSkills()) {
    const s = canonical.readSkill(meta.name);
    items.push({ id: meta.id, name: meta.name, text: s ? s.body : '', type: 'skill' });
  }
  return items;
}

// ---------- 사용량 조회(A 신호 + 상태 + LRU) ----------
function usage(now, thresholds) {
  const nowDate = now || defaultNow();
  telemetry.recompute(nowDate, thresholds); // A 재계산(사이드카 갱신)
  const rows = telemetry.list(nowDate, thresholds).map((x) => ({
    ...x,
    lastActivity: telemetry.latestActivity(x.telemetry),
  }));
  // LRU: 활동이 오래된(또는 없는) 순으로 정렬
  rows.sort((a, b) => (a.lastActivity || '').localeCompare(b.lastActivity || ''));
  return { now: nowDate.toISOString(), items: rows };
}

// ---------- 제안 staging 저장소 ----------
function proposalsPath() {
  return path.join(paths.canonicalRoot(), '.proposals.json');
}
function loadProposals() {
  try {
    return JSON.parse(fs.readFileSync(proposalsPath(), 'utf8')) || [];
  } catch {
    return [];
  }
}
function saveProposals(list) {
  fs.mkdirSync(paths.canonicalRoot(), { recursive: true });
  fs.writeFileSync(proposalsPath(), JSON.stringify(list, null, 2) + '\n');
}

// 모든 canonical 항목의 A 신호를 다시 계산하고, 상태를 전이해 사이드카를 갱신·반환한다.
//  - now: 활동/노후화 기준 시각(테스트 용이성을 위해 인자로 받는다). 생략 시 new Date().
//  - thresholds: {staleDays, archiveDays} 덮어쓰기(생략 시 설정 파일/상수).
// B 값은 보존한다(이 함수는 A만 갱신).
function recompute(now, thresholds) {
  const nowDate = now instanceof Date ? now : now ? new Date(now) : new Date();
  const th = loadThresholds(thresholds);

  const root = paths.canonicalRoot();
  const gitAvailable = isGitRepo(root);

  const data = load();
  const items = listItems();
  const seen = new Set();

  for (const item of items) {
    seen.add(item.id);
    const prev = data[item.id];
    const a = computeChangeSignal(item.file, root, gitAvailable);

    // signal_sources: A 출처('git'|'mtime')를 보장하고, 기존 B 출처(예: 'claude:transcript')는 유지.
    const prevSources = (prev && Array.isArray(prev.signal_sources) ? prev.signal_sources : []).filter(
      (s) => s !== 'git' && s !== 'mtime'
    );
    const signal_sources = [a.source, ...prevSources];

    // A 신호와 출처만 갱신(병합으로 B 보존). change_dates 도 A 재계산으로 갱신.
    let rec = mergeRecord(prev, {
      churn_count: a.churn_count,
      last_changed: a.last_changed,
      change_dates: Array.isArray(a.change_dates) ? a.change_dates : [],
      signal_sources,
    });

    // 상태 전이는 갱신된 A(+보존된 B)를 바탕으로 계산.
    rec.state = getState(rec, nowDate, th);
    data[item.id] = rec;
  }

  // canonical 에서 사라진 항목은 사이드카에 남겨둔다(이력/복구 목적). 삭제하지 않는다.

  save(data);
  return data;
}

// ---------- 조회 ----------

// 항목 목록 + telemetry + 상태를 합쳐 반환. 재계산은 하지 않고 현재 사이드카를 읽는다.
// 사이드카에 없는 항목은 기본 스키마로 채워 함께 반환한다.
function list(now, thresholds) {
  const nowDate = now instanceof Date ? now : now ? new Date(now) : new Date();
  const th = loadThresholds(thresholds);
  const data = load();

  return listItems().map((item) => {
    const telemetry = mergeRecord(data[item.id], {});
    return {
      id: item.id,
      kind: item.kind,
      telemetry,
      state: telemetry.pinned ? 'active' : getState(telemetry, nowDate, th),
    };
  });
}

