    const last = formatDateHuman(x.lastActivity);
    return `<tr>
      <td><span class="item-name">${esc(x.id)}</span></td>
      <td class="muted">${esc(x.kind)}</td>
      <td><span class="cell-pill ${x.state === 'stale' ? 'warn' : 'ok'}">${esc(stateKo(x.state))}</span></td>
      <td>${esc(String(x.telemetry.churn_count))}</td>
      <td class="muted" title="${esc(x.lastActivity || '')}">${esc(last)}</td>
    </tr>`;
  }).join('') : `<tr><td colspan="5" class="skel">항목 없음 — 먼저 가져오기 하세요
    <span class="inline-acts" style="justify-content:center;margin-top:10px"><button class="btn btn-secondary btn-sm" data-goto="skills">스킬 보기</button></span></td></tr>`;
}

async function loadPending() {
  showLoading('#proposal-inbox');
  let d;
  try { d = await api('/pending'); }
  catch { showLoadError('#proposal-inbox', loadPending); return; }
  setCount('usage', (d.proposals || []).length);
  const box = $('#proposal-inbox');
  if (!d.proposals.length) { box.innerHTML = '<div class="empty-state">대기 중인 제안 없음. (점검 실행으로 생성)</div>'; return; }
  box.innerHTML = d.proposals.map((p) => `
    <div class="card">
      <div style="display:flex;align-items:center;gap:8px">
        <span class="badge muted">${esc(p.kind)}</span>
        <span class="item-name">${esc(p.title)}</span>
      </div>
      <div class="muted" style="margin-top:6px;font-size:13px">${esc(p.detail)}</div>
      <div class="inline-acts" style="margin-top:12px">
        <button class="btn btn-primary btn-sm" data-approve-id="${esc(p.id)}">승인</button>
        <button class="btn btn-ghost btn-sm" data-reject-id="${esc(p.id)}">거절</button>
      </div>
    </div>`).join('');
}

async function runReview(dryRun) {
  let r;
  try { r = await api('/review', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ dryRun }) }); }
  catch (e) { toast('점검하지 못했습니다: ' + e.message); return; }
  const states = r.report.states || {};
  $('#review-result').textContent = `${dryRun ? '미리보기 완료 · 파일 변경 없음' : '점검 완료'} — 제안 ${r.report.counts.proposals}개 · 사용중 ${states.active || 0} · 오래됨 ${states.stale || 0} · 보관 ${states.archived || 0}`;
  loadPending();
  loadUsage();
  loadSyncLog();
}

// F6: 고정(pin)·보관(archive)·복구는 UI에서 제거 — 관찰 기반 화면으로 단순화.
// 서버 엔드포인트(/pin·/archive·/restore)는 그대로 두고 UI 진입점만 없앤다.
async function doApprove(id) {
  try { await api('/approve', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id }) }); }
  catch (e) { toast('적용하지 못했습니다: ' + e.message); return; }
  toast('승인됨'); loadPending(); loadUsage();
}
async function doReject(id) {
  try { await api('/reject', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ id }) }); }
  catch (e) { toast('적용하지 못했습니다: ' + e.message); return; }
  toast('거절됨'); loadPending();
}

