// ===================== 사용량(usage) =====================
// 사용빈도 전용 표. GET /usage → items[]{ id, kind, freq:{day1,day7,total}, lastActivity }.
// 백엔드 계약: 각 item에 freq(하루/일주일/전체 변경 횟수)가 붙는다. 배포 전 응답이나
// 구 사이드카에서는 freq가 없을 수 있으므로 항상 `?? 0`으로 안전하게 소비한다(크래시 금지, D26).
// 정렬: 전체 사용빈도(total) 내림차순. 동률은 최근 활동(lastActivity) 최신순. 0인 항목도 표시한다.
async function loadUsage() {
  showLoading('#usage-rows', 5);
  let u;
  try { u = await api('/usage'); }
  catch { showLoadError('#usage-rows', loadUsage, 5); return; }
  const freqOf = (x) => (x && x.freq) || {};
  const items = (u.items || []).slice().sort((a, b) => {
    const ta = freqOf(a).total ?? 0;
    const tb = freqOf(b).total ?? 0;
    if (tb !== ta) return tb - ta; // 전체 사용빈도 내림차순
    // 동률은 최근 활동순(최신이 위). 시각이 없는 항목은 맨 아래로.
    const la = a.lastActivity ? new Date(a.lastActivity).getTime() : 0;
    const lb = b.lastActivity ? new Date(b.lastActivity).getTime() : 0;
    return lb - la;
  });
  $('#usage-rows').innerHTML = items.length ? items.map((x) => {
    const f = freqOf(x);
    return `<tr>
      <td><span class="item-name">${esc(x.id)}</span></td>
      <td class="muted">${esc(x.kind)}</td>
      <td>${esc(String(f.day1 ?? 0))}</td>
      <td>${esc(String(f.day7 ?? 0))}</td>
      <td>${esc(String(f.total ?? 0))}</td>
    </tr>`;
  }).join('') : `<tr><td colspan="5" class="skel">항목 없음 — 먼저 가져오기 하세요
    <span class="inline-acts" style="justify-content:center;margin-top:10px"><button class="btn btn-secondary btn-sm" data-goto="skills">스킬 보기</button></span></td></tr>`;
}

