const totals=rows.map(r=>Number(r[4]));
let sortedDesc=true;for(let i=1;i<totals.length;i++){if(totals[i]>totals[i-1]){sortedDesc=false;break;}}
return {rowCount:rows.length,firstRows:rows.slice(0,4),totalsSorted:totals,sortedDesc};})()

(async()=>{
// track network via performance entries
location.hash='overview';await new Promise(r=>setTimeout(r,1400));
const lastsync=!!document.querySelector('#ov-lastsync');
const backupLink=!!document.querySelector('.backup-link');
const stats=[...document.querySelectorAll('#ov-stats .stat')].map(s=>s.querySelector('.stat-label')?.textContent);
const dist=[...document.querySelectorAll('#ov-dist .dist-row')].map(d=>d.textContent.replace(/\s+/g,' ').trim());
const bentoChildren=document.querySelectorAll('.bento > .widget').length;
const synclogCalls=performance.getEntriesByType('resource').filter(e=>e.name.includes('/synclog')).length;
return {ovLastsyncPresent:lastsync,backupLinkPresent:backupLink,statCount:stats.length,statLabels:stats,distTop5:dist,bentoWidgets:bentoChildren,synclogFetchCount:synclogCalls};})()

(async()=>{
location.hash='skills';await new Promise(r=>setTimeout(r,1600));
const folderItems=document.querySelectorAll('#skill-folder-list .mdf-item').length;
const mxRows=document.querySelectorAll('#skill-mx-rows tr').length;
const mxThs=[...document.querySelectorAll('#skill-mx-table thead th')].map(t=>t.textContent.trim());
// open a skill detail modal by clicking first row name cell
let modalOpened=false;
const firstRow=document.querySelector('#skill-mx-rows tr');
if(firstRow){firstRow.querySelector('.item-name')?.click(); await new Promise(r=>setTimeout(r,700));
  modalOpened=document.querySelector('#panel')?.classList.contains('open')||!document.querySelector('#content-viewer')?.hidden;}
return {folderItems,mxRows,mxThs,modalOpened};})()

(async()=>{
// close any open panel
document.querySelector('#panel-close')?.click();document.querySelector('#scrim')?.click();
location.hash='instructions';await new Promise(r=>setTimeout(r,1400));
const summary=document.querySelector('#instr-summary')?.textContent?.replace(/\s+/g,' ').trim()||'';
const hasContent=!!document.querySelector('#instr-cards .instr-content, #instr-cards .instr-single, #instr-cards .sxs, #instr-cards .instr-panes');
const errs=performance.getEntriesByType('resource').filter(e=>e.name.includes('/synclog')).length;
return {instrSummary:summary.slice(0,80),instrHasContent:hasContent,synclogCallsTotal:errs};})()

